const now = new Date();

// n8n should run this on Thursday.
// Report covers previous Thursday 00:00:00 through Wednesday 23:59:59.

const start = new Date(now);
start.setDate(now.getDate() - 7);
start.setHours(0, 0, 0, 0);

const end = new Date(now);
end.setDate(now.getDate() - 1);
end.setHours(23, 59, 59, 999);

const formatDate = (date) => {
  return date.toISOString();
};

return [
  {
    json: {
      report_start: formatDate(start),
      report_end: formatDate(end),
      report_label: `${start.toDateString()} - ${end.toDateString()}`
    }
  }
];

const range = $('Set Report Date Range').first().json;
const start = new Date(range.report_start);
const end = new Date(range.report_end);

const jobOpeningResponse = $('Zoho - Get Job Openings').first().json;
const applicationResponse = $('Zoho - Get Applications').first().json;
const interviewResponse = $('Zoho - Get Interviews').first().json;

const jobs = jobOpeningResponse.data || [];
const applications = applicationResponse.data || [];
const interviews = interviewResponse.data || [];

function normalizeLookup(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (value.name) return value.name;
  return String(value);
}

function isWithinRange(value) {
  if (!value) return false;
  const date = new Date(value);
  return date >= start && date <= end;
}

function getJobTitleFromJob(job) {
  return normalizeLookup(
    job.Job_Opening_Name ||
    job.Posting_Title ||
    job.Job_Title ||
    job['Job Opening Name']
  );
}

function getJobTitleFromApplication(app) {
  return normalizeLookup(
    app.Job_Opening_Name ||
    app.Posting_Title ||
    app.Job_Opening_ID
  );
}

function getJobTitleFromInterview(interview) {
  return normalizeLookup(interview.Job_Opening_Name);
}

function getClientFromJob(job) {
  return normalizeLookup(
    job.Client ||
    job.Client_Name ||
    job.Account_Name ||
    job.Department_Name ||
    job.Department ||
    job.Hiring_Manager_Details
  );
}

function getStatusFromJob(job) {
  return normalizeLookup(
    job.Job_Opening_Status ||
    job.Job_Status ||
    job.Status ||
    job.Publish
  );
}

function emptyRow(title = '') {
  return {
    'Job Title': title,
    'Client': '',
    'Total Candidates in Job Opening': 0,
    'Candidates Worked This Week': 0,
    'Candidates Invited to Book': 0,
    'Candidates Interviewed': 0,
    'Scheduled with Client': 0,
    'Job Opening Status': ''
  };
}

const reportByJob = {};

// 1. Create base rows from Job Openings
for (const job of jobs) {
  const title = getJobTitleFromJob(job);
  if (!title) continue;

  if (!reportByJob[title]) {
    reportByJob[title] = emptyRow(title);
  }

  reportByJob[title]['Client'] = getClientFromJob(job);
  reportByJob[title]['Job Opening Status'] = getStatusFromJob(job);
}

// 2. Add Application-based counts
for (const app of applications) {
  const title = getJobTitleFromApplication(app);
  if (!title) continue;

  if (!reportByJob[title]) {
    reportByJob[title] = emptyRow(title);
  }

  // All-time/current total candidates attached to the job opening
  reportByJob[title]['Total Candidates in Job Opening']++;

  // Weekly activity: application touched/updated this week
  if (isWithinRange(app.Updated_On) || isWithinRange(app.Last_Activity_Time)) {
    reportByJob[title]['Candidates Worked This Week']++;
  }

  // Weekly booking invite activity
  if (isWithinRange(app.Booking_Link_Sent_Date)) {
    reportByJob[title]['Candidates Invited to Book']++;
  }
}

// 3. Add Interview-based counts
for (const interview of interviews) {
  const title = getJobTitleFromInterview(interview);
  if (!title) continue;

  if (!reportByJob[title]) {
    reportByJob[title] = emptyRow(title);
  }

  if (!isWithinRange(interview.Start_DateTime)) continue;

  const status = String(interview.Interview_Status || '').toLowerCase();
  const interviewName = String(interview.Interview_Name || '').toLowerCase();

  // Candidates interviewed this week
  if (
    status.includes('completed') ||
    status.includes('complete') ||
    status.includes('conducted')
  ) {
    reportByJob[title]['Candidates Interviewed']++;
  }

  // Scheduled with client this week
  if (
    interviewName.includes('client') ||
    interviewName.includes('hiring manager') ||
    interviewName.includes('hm')
  ) {
    reportByJob[title]['Scheduled with Client']++;
  }
}

// 4. Sort and output rows
const rows = Object.values(reportByJob)
  .filter(row => row['Job Title'])
  .sort((a, b) => a['Job Title'].localeCompare(b['Job Title']));

return rows.map(row => ({ json: row }));
